"""Part V, Chapter 37 entries — infinite series supplement (curated LaTeX)."""

from __future__ import annotations

TOPICS_C37 = ["infinite-series-supplement"]


def rec(entry_id: str, content: str) -> dict:
    return {"id": entry_id, "content": content, "topics": TOPICS_C37}


CHAPTER_37 = [
    rec("RN-P5-C37-Entry01", r"Let $\varphi(z)$ be analytic for $\Re z>0$. Assume $\lim_{y\to\infty}|\varphi(x\pm iy)|e^{-2\pi y}=0$ uniformly on compact $x$-intervals in $[0,\infty)$, and that $\int_0^{\infty}|\varphi(x\pm iy)|e^{-\pi y}\,dy$ exists for each $x>0$ and tends to $0$ as $x\to\infty$. Then $\displaystyle\sum_{n=0}^{\infty}\varphi(n)=\int_0^{\infty}\varphi(t)\,dt+\tfrac12\varphi(0)+i\int_0^{\infty}\frac{\varphi(it)-\varphi(-it)}{e^{2\pi t}-1}\,dt$."),
    rec("RN-P5-C37-Entry02", r"Let $n$ be any complex number with $\Re n>\tfrac12$. Let $z^n$ have its principal value. If $\Re x>0$, then $\displaystyle\sum_{k=0}^{\infty}(k+x)^{-n}=\frac{\Gamma(n)x^{-n}}{2}+\frac{2}{(2\pi i)^{1-n}}\int_0^{\infty}\frac{t^{n-1}\cos(\pi t)}{e^{2\pi t}-1}\,dt$."),
    rec("RN-P5-C37-Entry03", r"Assume $\varphi(z)$ is analytic for $\Re z>0$. Let $a$ be real with $0<|a|<1$. If the hypotheses of Entry 1 hold and the integral converges, then $\displaystyle\frac{2}{\sin(\pi a)}\sum_{n=0}^{\infty}[\varphi(2n+1-a)-\varphi(2n+1+a)]=\int_0^{\infty}\frac{\varphi(ix)+\varphi(-ix)}{\cosh(\pi x)+\cos(\pi a)}\,dx$."),
    rec("RN-P5-C37-Entry04", r"Let $\varphi(z)$ be analytic for $\Re z>0$. Under the hypotheses of Entry 1, $\displaystyle\sum_{n=0}^{\infty}(-1)^n\varphi(2n+1)=\int_0^{\infty}\frac{\varphi(ix)+\varphi(-ix)}{\cosh(\pi x/2)}\,dx$."),
    rec("RN-P5-C37-Entry05", r"Let $\varphi(z)$ be analytic for $\Re z>0$. Under suitable decay hypotheses, $\displaystyle\varphi(0)+2\sum_{n=1}^{\infty}(-1)^n\varphi(n)=\int_0^{\infty}\frac{\varphi(ix)-\varphi(-ix)}{\sinh(\pi x)}\,dx$."),
    rec("RN-P5-C37-Entry06", r"Let $\varphi(z)$ be analytic for $\Re z>0$. Suppose the hypotheses of Entry 5 hold. Then $\displaystyle\sum_{n=0}^{\infty}(-1)^n\varphi(n)=\int_0^{\infty}\frac{\varphi(ix)-\varphi(-ix)}{\sinh(\pi x)}\,dx$."),
    rec("RN-P5-C37-Entry07", r"Let $\alpha,\beta>0$ with $\alpha\beta=\pi^2$ and $\Re n>2$. Then $\displaystyle\sum_{k=1}^{\infty}k^{-n}=\frac{\alpha^{n-1}}{2}\zeta(n)+\frac{\alpha^{n-1}}{\pi}\sum_{k=1}^{\infty}\frac{\Gamma((n-1)/2+k)}{k!\,\Gamma((n-1)/2)}\,{}_1F_1\!\left(\tfrac{n-1}{2}+k;\tfrac12;-(\pi k/\alpha)^2\right)$."),
    rec("RN-P5-C37-Entry08", r"Let $x>0$ and $-1<n<2$. Then $\displaystyle\sum_{k=1}^{\infty}k^{-n}=\frac{x^{n-1}}{2}\zeta(n)+\frac{2x^{n-1}}{\sqrt{\pi}}\sum_{k=1}^{\infty}\frac{\Gamma((n-1)/2+k)}{k!\,\Gamma((n-1)/2)}\,{}_1F_1\!\left(\tfrac{n-1}{2}+k;\tfrac12;-(\pi k/x)^2\right)$."),
    rec("RN-P5-C37-Entry09", r"Let $x$ be a positive nonintegral number and $0<n<1$. Then $\displaystyle\sum_{k=1}^{\infty}k^{-n}=\frac{x^{n-1}}{2}\zeta(n)+\frac{2x^{n-1}}{\sqrt{\pi}}\sum_{k=1}^{\infty}\frac{\Gamma((1-n)/2+k)}{k!\,\Gamma((1-n)/2)}\,{}_1F_1\!\left(\tfrac{1-n}{2}+k;\tfrac12;-(\pi k/x)^2\right)$."),
    rec("RN-P5-C37-Entry10", r"Let $x$ be positive and $0<n<1$. Then $\displaystyle\sum_{k=1}^{\infty}(-1)^{k-1}k^{-n}=\frac{(2x)^{n-1}}{2}\,(1-2^{1-n})\zeta(n)+\frac{2(2x)^{n-1}}{\sqrt{\pi}}\sum_{k=1}^{\infty}\frac{\Gamma((1-n)/2+k)}{k!\,\Gamma((1-n)/2)}\,{}_1F_1\!\left(\tfrac{1-n}{2}+k;\tfrac12;-(\pi k/x)^2\right)$."),
    rec("RN-P5-C37-Entry11", r"Let $\varphi(z)$ be an entire function. Let $C_n$ denote a positively oriented circle of radius $n$ centered at the origin. If $\lim_{n\to\infty}\int_{C_n}\varphi(z)\cot(\pi z)\,dz=0$, then $\displaystyle\sum_{k=-\infty}^{\infty}\varphi(k)=-\sum_{\rho}\Res_{\rho}\varphi(z)\cot(\pi z)$, where the sum is over all poles of $\varphi(z)\cot(\pi z)$."),
    rec("RN-P5-C37-Entry12", r"If $n$ is any positive integer, then $\displaystyle\sum_{k=1}^{\infty}\frac{(-1)^{k-1}}{k^{2n}}=\frac{(-1)^{n-1}(2^{2n-1}-1)\pi^{2n}B_{2n}}{(2n)!}$."),
    rec("RN-P5-C37-Entry13", r"If $n$ is an odd positive integer, then $\displaystyle\sum_{k=1}^{\infty}\frac{1}{k^{2n}}=\frac{(-1)^{(n-1)/2}(2\pi)^{2n}B_{2n}}{2(2n)!}$."),
    rec("RN-P5-C37-Entry14", r"Let $\varphi(z,x)=\varphi(z)$ be defined by (14.2). Then $\displaystyle\sum_{k=1}^{\infty}\varphi(k,x)=\int_0^{\infty}\varphi(t,x)\,dt+\tfrac12\varphi(0,x)-\sum_{k=1}^{\infty}\frac{B_{2k}}{(2k)!}\varphi^{(2k-1)}(0,x)$."),
    rec("RN-P5-C37-Entry15", r"$\displaystyle\sum_{k=1}^{\infty}\frac{k^{n-1}|B_{2k}||B_{2n}|}{\Gamma(2k)\Gamma(2n)}\left(\frac{\pi}{4}\right)^{2k+2n}=\frac{2\cos(n\tan^{-1}\tfrac14)}{2\cos(n\tan^{-1}\tfrac12)}-\frac{2\cos(n\tan^{-1}\tfrac13)}{2\cos(n\tan^{-1}\tfrac23)}+\cdots$, where $n$ is an even positive integer and the numerators are sums of squares of coprime integers."),
    rec("RN-P5-C37-Entry15-Theorem01", r"Let $m$ be a positive integer. Then $\displaystyle\sum_{k=1}^{\infty}\frac{k^{4m-1}}{(e^{2\pi k}-1)(8m-1)!}=\frac{1}{8m(4m)}\sum_{\ell>2}\sum_{c^2+d^2=\ell}\frac{2\cos(4m\tan^{-1}(d/c))}{(c^2+d^2)^{2m}}$, where the inner sum is over distinct coprime representations."),
    rec("RN-P5-C37-Entry16", r"$\displaystyle\sum_{k=1}^{\infty}\frac{k^{n-1}|B_{2k}||B_{2n}|}{\Gamma(2k)\Gamma(2n)}\left(\frac{\pi}{4}\right)^{2k+2n}=\sum_{\ell}\frac{2\cos(n\tan^{-1}(d/c))}{(c^2+d^2)^{n/2}}$, summed over distinct solutions of $c^2+d^2=\ell$ with $\gcd(c,d)=1$."),
    rec("RN-P5-C37-Entry16-Theorem01", r"Let $m$ be a positive integer. Then $\displaystyle\sum_{k=1}^{\infty}\frac{k^{2m-1}}{(e^{2\pi k}-1)(4m-1)!}=\frac{1}{4m(2m)}\sum_{\ell>1}\sum_{c^2+d^2=\ell}\frac{2\cos(2m\tan^{-1}(d/c))}{(c^2+d^2)^m}$."),
    rec("RN-P5-C37-Entry17", r"$\displaystyle\sum_{k=1}^{\infty}\frac{(-1)^{k-1}k^{n-1}}{(e^{\pi k}-1)(n-1)!}=\frac{1}{n}\left[\frac{1}{2}-\frac{2\cos(n\tan^{-1}\tfrac13)}{2\cos(n\tan^{-1}\tfrac23)}+\cdots\right$, where $n$ is an even positive integer."),
    rec("RN-P5-C37-Entry17-Theorem01", r"Let $m$ be a positive integer with $m\not\equiv 0\pmod 3$. Then $\displaystyle\sum_{k=1}^{\infty}\frac{(-1)^{k-1}k^{2m-1}}{(e^{\pi k}-1)(2m-1)!}=\frac{1}{2m}\sum_{\ell>1}\sum_{c^2+d^2=3\ell}\frac{2\cos(2m\tan^{-1}(d/c))}{(c^2+d^2)^m}$."),
    rec("RN-P5-C37-Entry18", r"$\displaystyle\sum_{k=1}^{\infty}\frac{(-1)^{k-1}k^{n-1}}{(e^{\pi k/2}-1)(n-1)!}=\frac{2}{n}\left[\frac{1}{2}-\frac{2\cos(n\tan^{-1}\tfrac12)}{2\cos(n\tan^{-1}1)}+\cdots\right$, where $n$ is an even positive integer."),
    rec("RN-P5-C37-Entry18-Lemma01", r"Let $\Im z>0$ and let $n$ be a positive integer exceeding $1$. Then $\displaystyle\sum_{k=1}^{\infty}\frac{k^{n-1}}{e^{2\pi k/z}-1}=\frac{z^n}{2}\sum_{k=1}^{\infty}\frac{k^{n-1}}{e^{2\pi k z}-1}+\text{lower-order terms involving class numbers.}$"),
    rec("RN-P5-C37-Entry18-Theorem01", r"If $m$ is a positive integer, then $\displaystyle\sum_{k=1}^{\infty}\frac{(-1)^{k-1}k^{2m-1}}{(e^{\pi k/2}-1)(2m-1)!}=\frac{2}{2m}\sum_{\ell>1}\sum_{c^2+d^2=4\ell}\frac{2\cos(2m\tan^{-1}(d/c))}{(c^2+d^2)^m}$."),
    rec("RN-P5-C37-Entry19", r"$\displaystyle\sum_{k=1}^{\infty}\frac{(-1)^{k-1}k^{n-1}}{(e^{\pi k/3}-1)(n-1)!}=\frac{3}{n}\left[\frac{1}{2}-\frac{2\cos(n\tan^{-1}\tfrac23)}{2\cos(n\tan^{-1}\tfrac43)}+\cdots\right$, where $n$ is an even positive integer."),
    rec("RN-P5-C37-Entry19-Theorem01", r"Let $m$ be a positive integer with $m\not\equiv 0\pmod 3$. Then $\displaystyle\sum_{k=1}^{\infty}\frac{(-1)^{k-1}k^{2m-1}}{(e^{\pi k/3}-1)(2m-1)!}=\frac{3}{2m}\sum_{\ell>1}\sum_{c^2+d^2=9\ell}\frac{2\cos(2m\tan^{-1}(d/c))}{(c^2+d^2)^m}$."),
    rec("RN-P5-C37-Entry20", r"If $n$ is a positive integer, then $\displaystyle\sum_{k=1}^{\infty}\frac{k^{n-1}}{(e^{2\pi k/\sqrt{2}}-1)(n-1)!}=\frac{\sqrt{2}}{n}\left[\frac{1}{2}-\frac{2\cos(n\tan^{-1}\tfrac12)}{2\cos(n\tan^{-1}1)}+\cdots\right$."),
    rec("RN-P5-C37-Entry21", r"Let $n$, $a$, and $\beta$ be positive with $\alpha\beta=2\pi$. Then $\displaystyle\sum_{k=1}^{\infty}\frac{k^{n-1}}{(e^{\alpha k}-1)(n-1)!}=\frac{1}{n}\left[\frac{\alpha^{n-1}}{2}+\sum_{j=1}^{\infty}\frac{2\cos(n\tan^{-1}(\beta j/\alpha))}{(1+(\beta j/\alpha)^2)^{n/2}}\right]$ and a companion formula with $\alpha$ and $\beta$ interchanged."),
    rec("RN-P5-C37-Entry22", r"Let $\psi(x)=\Gamma'(x)/\Gamma(x)$. If $x>0$, then $\displaystyle\psi(x+1)=-\gamma+\sum_{k=1}^{\infty}\left(\frac{1}{k}-\frac{1}{k+x}\right)$, and as $x\to\infty$, $\displaystyle\psi(x+1)=\log x-\frac{1}{2x}-\frac{1}{12x^2}+\frac{1}{120x^4}-\frac{1}{252x^6}+\pi\log|2\sin(\pi x)|+\sum_{k=1}^{\infty}\frac{2\cos(2\pi kx)}{k^2\sinh(\pi k)}$."),
    rec("RN-P5-C37-Entry23", r"For each positive integer $n$, let $S_{2n}(q)=\sum_{k=1}^{\infty}\sigma_{2n-1}(k)q^k$ where $\Im q>0$. If $m$ is a positive integer, then $\displaystyle\frac{(4m+5)(4m-2)}{24(4m+2)(4m+1)}S_{4m+4}(q)=\sum_{k=1}^{4m+2}S_{4k}(q)S_{4m+4-k}(q)$."),
    rec("RN-P5-C37-Entry24", r"For each positive integer $n$, $\displaystyle\varphi_1(n)=-\frac{\zeta(3/2)}{\sqrt{n}}+\frac{1}{2\sqrt{n}}+\frac{1}{2}\sum_{k=1}^{\infty}\left[\sqrt{n+k}+\sqrt{n+k+1}-\sqrt{2n+k}-\sqrt{2n+k+1}\right]$."),
    rec("RN-P5-C37-Entry27", r"Let $\displaystyle\varphi(t)=\sum_{n=0}^{\infty}\frac{(-1)^n t^{2n+1}}{(2n+1)^2}$ for $|t|<1$. Then for every real $x$, $\displaystyle\frac{1}{2}\{\varphi(1)-\varphi(e^{-\pi x})\}-x\tan^{-1}(e^{-\pi x})=\sum_{n=0}^{\infty}(-1)^n(2n+1)\log|1+e^{-(2n+1)\pi x}|$."),
    rec("RN-P5-C37-Entry28", r"$\displaystyle\sum_{n=0}^{\infty}\frac{(-1)^n(2n+1)}{n^2}\log\bigl(1+(2+\sqrt{3})^{-(2n+1)}\bigr)=\tfrac12 G$, where $G$ is Catalan's constant."),
    rec("RN-P5-C37-Entry29", r"If $-1<x<1$, then $\displaystyle\sum_{n=0}^{\infty}(-1)^n(2n+1)\log|1+x^{2n+1}|=\tfrac{\pi}{4}\log\left(\frac{1+x}{1-x}\right)$."),
    rec("RN-P5-C37-Entry30", r"Let $\alpha>0$ and $0<\beta<1$ with $\alpha\beta=\pi$. Then $\displaystyle\sum_{n=0}^{\infty}(-1)^n(2n+1)\log|1+e^{-(2n+1)\alpha}|=\tfrac{\pi}{4}\log\left(\frac{1+e^{-\beta}}{1-e^{-\beta}}\right)$."),
    rec("RN-P5-C37-Entry31", r"For $x>0$, let $\displaystyle f(x)=\sum_{n=1}^{\infty}\frac{(-1)^{n-1}}{n}\,e^{-n^2 x^2/4}$. Then $f(x)=\sqrt{\pi}\sum_{n=1}^{\infty}\frac{(-1)^{n-1}}{n}e^{-\pi^2 n^2/x^2}$."),
    rec("RN-P5-C37-Entry32", r"If $\alpha,\beta>0$ with $\alpha\beta=\pi^2/4$, then $\displaystyle\sum_{n=1}^{\infty}\frac{(-1)^{n-1}n}{n^2+x^2}=\frac{\pi}{2}\,\frac{\sinh(2\alpha x)}{\cosh(2\alpha x)+\cos(2\beta x)}$."),
    rec("RN-P5-C37-Entry33", r"If $\alpha\beta=\pi^2/12$ where $\alpha,\beta>0$, then $\displaystyle\sum_{n=1}^{\infty}\frac{(-1)^{n-1}n}{n^2+x^2}=\frac{\pi}{2}\,\frac{\sinh(2\alpha x)}{\cosh(2\alpha x)+\cos(2\beta x)}$."),
    rec("RN-P5-C37-Entry34", r"Formally, $\displaystyle\sum_{n=1}^{\infty}\frac{(-1)^{n-1}}{n^s}=\frac{1}{\Gamma(s)}\int_0^{\infty}\frac{t^{s-1}}{e^t+1}\,dt$ for $\Re s>0$."),
    rec("RN-P5-C37-Entry35", r"Let $\alpha\beta=2\pi$ where $\alpha,\beta>0$. Let $\hat{\varphi}(n)=\int_0^{\alpha}\varphi(x)\cos(nx)\,dx$. Then $\displaystyle\frac{\alpha}{2}\sum_{n=1}^{\infty}\mu(n)\varphi(\alpha/n)=\sum_{n=1}^{\infty}\mu(n)\hat{\varphi}(\beta/n)$."),
    rec("RN-P5-C37-Entry36", r"If $p>0$, then $\displaystyle\sum_{n=1}^{\infty}\frac{\mu(n)}{n^2+p^2}=\frac{\pi}{2p}\,\frac{1}{K_1(p)}$, where $K_1$ is a modified Bessel function."),
    rec("RN-P5-C37-Entry37", r"If $p>0$, then $\displaystyle\sum_{n=1}^{\infty}\frac{(-1)^n\mu(n)}{n^2+p^2}=\frac{\pi}{2p}\,\frac{1}{I_1(p)}$, where $I_1$ is a modified Bessel function."),
    rec("RN-P5-C37-Entry38", r"Let $\varphi(z)$ be an entire function and put $\displaystyle f(z)=\sum_{n=0}^{\infty}\frac{(-1)^n(2n+1)\varphi(p(2n+1))}{(2n+1)!}\,\frac{\zeta(2n+1)}{\zeta(2n+2)}$, where $p\neq 0$. Under suitable hypotheses, $f(z)$ equals a sum over nonreal zeros $\rho$ of $\zeta(z)$ of $\varphi(\rho)\rho^p/(\Gamma(\tfrac12\rho+1)\cos(\tfrac12\pi\rho)\zeta'(\rho))$."),
    rec("RN-P5-C37-Entry39", r"Let $\varphi(z)$ be an entire function and put $\displaystyle f(z)=\sum_{n=0}^{\infty}\frac{(-1)^n(2n+1)\varphi(p(2n+1))}{(2n+1)!}\,\frac{\zeta(2n+1)}{\zeta(2n+2)}$. Under suitable hypotheses, $f(z)=\sum_{\rho}\varphi(\rho)\rho^p/(\Gamma(\tfrac12(\rho+1))\cos(\tfrac12\pi\rho)\zeta'(\rho))$ over nonreal zeros $\rho$ of $\zeta(z)$."),
    rec("RN-P5-C37-Entry40", r"For each positive integer $n$, $\displaystyle\sum_{k=1}^{\infty}\frac{(-1)^{k-1}}{(4k-2)^{2n}}=\frac{(-1)^{n-1}2^{1-2n}\pi^{2n}B_{2n}}{(2n)!}\sum_{j=0}^{n-1}\binom{2n-1}{j}\frac{E_j}{2^j}$, where $E_j$ are Euler numbers."),
    rec("RN-P5-C37-Entry41", r"For each positive integer $n$, $\displaystyle\sum_{k=0}^{\infty}\tan^{-1}\frac{1}{(2n+2k+1)\sqrt{3}}=\tan^{-1}\frac{1}{(2n+1)\sqrt{3}}+\sum_{k=1}^{\infty}\tan^{-1}\frac{2}{(2n+2k)(2n+2k+1)\sqrt{3}}$."),
    rec("RN-P5-C37-Entry42-Lemma01", r"Let $\Im z>0$. Then $\displaystyle\sum_{n=1}^{\infty}\frac{(-1)^{n-1}}{n^s}=\frac{1}{\Gamma(s)}\int_0^{\infty}\frac{t^{s-1}}{1+e^t}\,dt$ provides a convergent representation for alternating zeta values."),
    rec("RN-P5-C37-Entry42-Lemma02", r"Let $k>2$. Let $a_1,a_2,\ldots,a_k$ be constants with $0<a_k<\cdots<a_1<1$ and $a_1+\cdots+a_k=k-1$. Let $C_k(n)$ be defined by (42.11). Then partial sums of $\sum_{n=k}^{\infty}(-1)^{n-k}C_k(n)$ oscillate with amplitude controlled by $\Gamma(1-a_1)\cdots\Gamma(1-a_k)$."),
    rec("RN-P5-C37-Entry42", r"Let $k>2$. Suppose $a_1,\ldots,a_k$ satisfy $0<a_k<\cdots<a_1<1$ and $a_1+\cdots+a_k=k-1$. Let $C_k(n)$ be defined by (42.11). Then even and odd indexed partial sums of $\sum_{n=k}^{\infty}(-1)^{n-k}C_k(n)$ tend to $S_k+T_k$ and $S_k-T_k$, respectively, where $S_k=(-1)^k(1-2^{1-a_1})\Gamma(1-a_1)\cdots(1-2^{1-a_k})\Gamma(1-a_k)$ and $T_k=\Gamma(1-a_1)\cdots\Gamma(1-a_k)$."),
    rec("RN-P5-C37-Entry42-Corollary", r"Let $C_k(n)$ be given by (42.11) with $a_j=1-1/k$ for $1\le j\le k$. Then even and odd indexed partial sums of $\sum_{n=k}^{\infty}(-1)^{n-k}C_k(n)$ tend to $S_k+\pi T_k/\Gamma(1/k)$ and $S_k-\pi T_k/\Gamma(1/k)$, respectively. For $k=2$, they tend to $S_2+\pi/2$ and $S_2-\pi/2$."),
    rec("RN-P5-C37-Entry43", r"$e^{\alpha x}$ can be expanded in ascending powers of $e^{\pi x}-e^{-\pi x}$ and hence in ascending powers of $e^{\pi x}\sin x$; consequently many transcendental equations can be solved."),
    rec("RN-P5-C37-Entry44", r"Let $n$ be complex, $c$ be real, and $b>0$. If $0<x<(1/c)\tan^{-1}(c/b)$, then $\displaystyle\sum_{k=0}^{\infty}d_k\sin^k(cx)=\frac{1+\sin(cx)}{1-\sin(cx)}$, where $d_k$ are given by a product formula involving $n$, $b$, and $c$."),
    rec("RN-P5-C37-Entry45", r"Let $f$ be any differentiable function and set $u(q)=f(M(q)/N(q))$, where $M$ and $N$ are Eisenstein series. Then $\displaystyle q\frac{du}{dq}=\frac{n}{12}L(q)u(q)$ is a function of only $M$ and $N$."),
    rec("RN-P5-C37-Entry45-Corollary", r"$\displaystyle\frac{d(L^2/M)}{dM}=\frac{2L^2}{M^2}$ and $\displaystyle\frac{d(L^2/N)}{dN}=\frac{3L^2M}{2N^2}$."),
    rec("RN-P5-C37-Entry46", r"For $\Re a>0$, $\displaystyle\sum_{n=0}^{\infty}\frac{(-1)^n}{(n+a)^{2k+1}}=\frac{(-1)^k\pi^{2k+1}}{(2k)!}\,{}_2F_1\!\left(k+\tfrac12,k+1;k+\tfrac32;-a^2\right)$."),
    rec("RN-P5-C37-Entry47", r"For $|x|<1$, $\displaystyle\sum_{n=0}^{\infty}\frac{x^{n(n+1)/2}}{(1-x)(1-x^2)\cdots(1-x^n)}=\frac{1}{1-x-x^2-x^{2n+1}}+\cdots$."),
    rec("RN-P5-C37-Entry48", r"For $|x|<1$ and integers $n>2$, the polylogarithm $\Li_n(x)=\sum_{k=1}^{\infty}x^k/k^n$ satisfies $\displaystyle\Li_n(x)=(-1)^{n-1}\int_0^x\frac{\log^{n-1}(1-t)}{t}\,dt$ for $x>0$."),
    rec("RN-P5-C37-Entry49", r"If $|x|<1$, then $\displaystyle\sum_{k=1}^{\infty}\frac{x^k}{k}\coth(k\pi)=\frac{\pi}{2}+\sum_{k=1}^{\infty}\frac{(-1)^k\zeta(2k)x^{2k+2}}{k+1}$."),
    rec("RN-P5-C37-Entry50a", r"Let $\{a_n\}$ and $\{E_n\}$ be defined by (50.6) and (50.7), respectively. Set $E_n=\exp(\exp(\cdots\exp(a_n)))$. If $|a_n|<(1/e)^{1/e}$ for all $n$, then the infinite exponential converges."),
    rec("RN-P5-C37-Entry50b", r"Let $\{E_n\}$ be defined by (50.7). If $|a_n|\le (1/e)^{1/e}$ for all $n$, then the infinite exponential converges; this bound is best possible."),
    rec("RN-P5-C37-Entry50-Theorem01", r"Let $\{a_n\}$ and $\{E_n\}$ be given by (50.6) and (50.7), respectively. Set $A=\sup|a_n|$. If $A<(1/e)^{1/e}$, then $\{E_n\}$ converges; if $A>(1/e)^{1/e}$, then $\{E_n\}$ diverges."),
    rec("RN-P5-C37-Entry50-Lemma02", r"Let $\{x_n\}$, $n\ge 1$, be a sequence of real numbers with $x_n>1$. If $\sum_{n=1}^{\infty}\log\log x_n<\infty$, then the iterated exponential converges."),
    rec("RN-P5-C37-Entry50-Lemma03", r"Let $T_n^*$, $C_n^*$, and $X_n^*$ be defined by (50.14)–(50.16). Then $T_n^*\to 0$ as $n\to\infty$ if $|a_n|<(1/e)^{1/e}$."),
    rec("RN-P5-C37-Entry50-Lemma04", r"Let $r_n^*$ and $X_n^*$ be defined by (50.14) and (50.16). Then $|r_n^*|\le |a_n|$ and $|X_n^*|\le |a_n|^{1/e}$ for all $n$."),
    rec("RN-P5-C37-Entry50-Lemma05", r"Let $\{E_n\}$ be as in Entry 50a. If $|a_n|\le (1/e)^{1/e}$ for all $n$, then $|E_n-E_{n-1}|\le C|a_n|^{1/e}$ for a constant $C$ independent of $n$."),
]
